#include <iostream>
#include <string>
using namespace std;

int numSub(string s) {
    int count = 0;
    int mod = 1000000007; // 10^9 + 7

    for (int i = 0; i < s.length(); i++) {
        if (s[i] == '1') {
            count += (s.length() - i - 1);
        }
    }

    return count % mod;
}

int main() {
    string s = "0110111";
    cout << numSub(s);
    return 0;
}
